class Solution(object):
    def asteroidCollision(self, asteroids):
        stack = []
        for ast in asteroids:
            destoryed = False  # 标记当前行星是否被撞毁（默认False）
            # 栈不为空/栈顶向右/当前向左 发生碰撞
            while stack and stack[-1] > 0 and ast < 0 and not destoryed:
                if abs(ast) > abs(stack[-1]):
                    stack.pop()
                elif abs(ast) < abs(stack[-1]):
                    destoryed = True
                else:
                    stack.pop()
                    destoryed = True

            if not destoryed:
                stack.append(ast)
        return stack
        """
        :type asteroids: List[int]
        :rtype: List[int]
        """

class Solution(object):
    def equalPairs(self, grid):
        ans = 0
        for x in zip(*grid):
            lx = list(x)
            for y in grid:
                if lx == y:
                    ans += 1
        return ans
        """
        :type grid: List[List[int]]
        :rtype: int
        """

class Solution(object):
    def increasingTriplet(self, nums):
        # 维护两个变量，first和second，分别表示当前遍历到的元素之前的最小值和次小值
        # 如果当前元素大于second，说明存在递增三元组，返回True
        # 否则，更新first和second
        first = second = float('inf')
        for num in nums:
            if num > second:
                return True
            elif num > first:
                second = num
            else:
                first = num
        return False
        """
        :type nums: List[int]
        :rtype: bool
        """

class Solution(object):
    def findDuplicate(self, nums):
        # 快慢指针
        fast = slow = 0
        while True:
            fast = nums[nums[fast]]
            slow = nums[slow]
            if slow == fast:
                # 重置快指针到起点，相遇点是环的入口
                fast = 0;
                while nums[slow] != nums[fast]:
                    fast = nums[fast]
                    slow = nums[slow]
                return nums[slow]
        """
        :type nums: List[int]
        :rtype: int
        """

class Solution(object):
    def nextPermutation(self, nums):
        i = len(nums) - 2
        while i >= 0 and nums[i] >= nums[i + 1]:
            i -= 1
        if i >= 0:
            j = len(nums) - 1
            while j >= 0 and nums[i] >= nums[j]:
                j -= 1
            nums[i], nums[j] =  nums[j], nums[i]

        left, right = i + 1, len(nums) - 1
        while left < right:
            nums[left], nums[right] = nums[right], nums[left]
            left += 1
            right -= 1
        """
        :type nums: List[int]
        :rtype: None Do not return anything, modify nums in-place instead.
        """

class Solution(object):
    def sortColors(self, nums):
        # 用三个指针记录区域尾部
        num0 = num1 = num2 = 0
        for i in range(len(nums)):
            if nums[i] == 0:
                nums[num2] = 2; num2 += 1
                nums[num1] = 1; num1 += 1
                nums[num0] = 0; num0 += 1
            elif nums[i] == 1:
                nums[num2] = 2; num2 += 1
                nums[num1] = 1; num1 += 1
            else:
                nums[num2] = 2; num2 += 1
        """
        :type nums: List[int]
        :rtype: None Do not return anything, modify nums in-place instead.
        """

class Solution(object):
    def majorityElement(self, nums):
        hash_map = {}
        for num in nums:
            if num in hash_map:
                hash_map[num] += 1
            else:
                hash_map[num] = 1
        for key, value in hash_map.items():
            if value > len(nums) // 2:
                return key
        return nums[0]
        """
        :type nums: List[int]
        :rtype: int
        """

class Solution(object):
    def singleNumber(self, nums):
        hash_map = {}
        for num in nums:
            if num in hash_map:
                hash_map[num] += 1
            else:
                hash_map[num] = 1
        for key, value in hash_map.items():
            if value == 1:
                return key
        return -1
        """
        :type nums: List[int]
        :rtype: int
        """

class Solution(object):
    def minDistance(self, word1, word2):
        m = len(word1)
        n = len(word2)
        if n * m == 0:
            return n + m
        dp = [[0] * (n + 1) for _ in range(m + 1)]

        for i in range(m + 1):  # 边界初始化
            dp[i][0] = i
        for j in range(n + 1):
            dp[0][j] = j
        for i in range(1, m + 1):
            for j in range(1, n + 1):
                if word1[i - 1] != word2[j - 1]:
                    dp[i - 1][j - 1] += 1
                dp[i][j] = min(dp[i - 1][j] + 1,
                               dp[i][j - 1] + 1,
                               dp[i - 1][j - 1]
                            )

        return dp[m][n]
        """
        :type word1: str
        :type word2: str
        :rtype: int
        """

class Solution(object):
    def longestCommonSubsequence(self, text1, text2):
        m, n = len(text1), len(text2)
        dp = [[0] * (n + 1) for _ in range(m + 1)]

        for i in range(1, m + 1):
            for j in range(1, n + 1):
                if text1[i - 1] == text2[j - 1]:
                    dp[i][j] = dp[i - 1][j - 1] + 1
                else:
                    dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

        return dp[m][n]

        """
        :type text1: str
        :type text2: str
        :rtype: int
        """

class Solution(object):
    def lengthOfLIS(self, nums):
        if not nums:
            return 0
        dp = []
        for i in range(len(nums)):
            dp.append(1)
            for j in range(i):
                if nums[i] > nums[j]:
                    dp[i] = max(dp[i], dp[j] + 1)
        return max(dp)

        """
        :type nums: List[int]
        :rtype: int
        """

class Solution(object):
    def wordBreak(self, s, wordDict):
        dp = [False] * (len(s) + 1)
        dp[0] = True
        for j in range(1, len(s) + 1):
            for word in wordDict:
                if j >= len(word):
                    dp[j] = dp[j] or (dp[j - len(word)]) and word == s[j - len(word):j] 
        return dp[len(s)]
        """
        :type s: str
        :type wordDict: List[str]
        :rtype: bool
        """

class Solution(object):
    def coinChange(self, coins, amount):
        dp = [amount + 1] * (amount + 1)
        dp[0] = 0
        for i in range(amount + 1):
            for coin in coins:
                if i - coin < 0:
                    continue
                dp[i] = min(dp[i], dp[i - coin] + 1)

        return -1 if dp[amount] == (amount + 1) else dp[amount]
        """
        :type coins: List[int]
        :type amount: int
        :rtype: int
        """

class Solution(object):
    def generate(self, numRows):
        a = []
        for i in range(numRows):
            if i == 0:
                a.append([1])
            else:
                row = [1] * (i + 1)
                for j in range(1, i):
                    row[j] = a[i - 1][j - 1] + a[i - 1][j]
                a.append(row)
        return a
        """
        :type numRows: int
        :rtype: List[List[int]]
        """
